	/**
         * Normalize an icon name, resolving aliases when present.
         *
         * @param string $name Raw icon name.
         * @return string
         */
        public static function normalize_name( $name ) {
                $name = sanitize_key( (string) $name );

                if ( isset( self::$aliases[ $name ] ) ) {
                        return self::$aliases[ $name ];
                }

                return $name;
        }

        /**
         * Determine whether an icon exists in the internal registry.
         *
         * @param string $name Icon slug or alias.
         * @return bool
         */
        public static function has_icon( $name ) {
                $name = self::normalize_name( $name );
                return isset( self::$icons[ $name ] );
        }

        /**
         * Return all available icon names.
         *
         * @return string[]
         */
        public static function all_icon_names() {
                $names = array_keys( self::$icons );
                sort( $names );
                return $names;
        }

        /**
	 * Return inline SVG markup for $name.
	 *
	 * @param string $name   Icon slug (FA6 or accepted FA5 alias).
	 * @param string $class  Extra CSS classes for the <svg> element.
	 * @param string $title  Accessible title text. Empty = aria-hidden.
	 * @return string        Safe SVG string, or '' if icon unknown.
	 */
	public static function svg( $name, $class = '', $title = '' ) {
                $name = self::normalize_name( $name );

		if ( ! isset( self::$icons[ $name ] ) ) {
			return '';
		}

		$d   = self::$icons[ $name ];
		$cls = trim( 'tm-icon tm-icon-' . esc_attr( $name ) . ( $class ? ' ' . esc_attr( $class ) : '' ) );

		if ( $title ) {
			$tid  = 'tm-icon-title-' . esc_attr( $name );
			$aria = 'role="img" aria-labelledby="' . $tid . '"';
			$tel  = '<title id="' . $tid . '">' . esc_html( $title ) . '</title>';
		} else {
			$aria = 'aria-hidden="true" focusable="false"';
			$tel  = '';
		}

		return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="' . esc_attr( $d['vb'] ) . '" '
			. 'class="' . $cls . '" style="fill:currentColor" ' . $aria . '>'
			. $tel . $d['p'] . '</svg>';
	}
}

/**
 * Shorthand template function.
 *
 * @param string $name
 * @param string $class
 * @param string $title
 * @return string
 */
function tm_svg_icon( $name, $class = '', $title = '' ) {
	return TM_Icons::svg( $name, $class, $title );
}
